var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>어둠의 해커 9인방. 통칭 다─크 세븐.</b>","JPN":"<b>闇のハッカー9人組。通称ダークセブン。</b>","ENG":"<b>The Nine Great Hackers of Darkness. A.K.A. Daark Seven.</b>","TWN":"<b>黑暗的駭客9人幫。通稱Dark 7。</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>그들은 사회의 이면에서 암약하며 기업의 횡포와 범죄 조직의 악행을 폭로한다.</b>","JPN":"<b>彼らは社会の裏側で暗躍し、企業の横暴と犯罪組織の悪行を暴露する。</b>","ENG":"<b>They remain hidden among us as they expose the machinations of multinational conglomerates and criminal organizations.</b>","TWN":"<b>他們在社會裡暗中活躍，揭露企業的橫行與犯罪組織的惡行。</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>알파트릭스의 무차별적인 경제 침공이 갑작스럽게 중단된 것도,</b>","JPN":"<b>アルファトリックスの無差別的な経済侵攻が突然中断したのも、</b>","ENG":"<b>The wanton economic invasion of Alphatrix came to a halt,</b>","TWN":"<b>阿爾法崔克斯無差別的經濟侵略突然中斷也是,</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>사악한 악의 조직 리플레이서 신디케이트를 파멸로 몰아 넣은 것도,</b>","JPN":"<b>腹黒い悪の組織リプレイサー・シンジケートを破滅に追いやったのも、</b>","ENG":"<b>and the evil Replacer Syndicate met its doom,</b>","TWN":"<b>邪惡組織克隆集團被逼入絕境也是,</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>그 이면에는 모두 다─크 세븐의 활약이 있었다.</b>","JPN":"<b>その裏側にはいつもダークセブンの活躍があった。</b>","ENG":"<b>all thanks to the behind-the-scene efforts of Daark Seven.</b>","TWN":"<b>甚至在異界都有Dark 7活躍的身影。</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<b>그렇다! 다─크 세븐은 바로 왜곡된 체제에 저항하는 고독한 다─크 히어로인 것이다!</b>","JPN":"<b>そう！　ダークセブンは歪曲された体制に抵抗する孤独なダークヒーローなのである！</b>","ENG":"<b>That's right! Daark Seven is our unsung Dark Hero resisting against the nefarious system!</b>","TWN":"<b>沒錯！Dark 7正是抵抗這世間扭曲體制的黑暗英雄！</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"들을 때마다 쪽팔려 죽겠네, 진짜.","JPN":"本当、何回聞いても恥ずかしいわ。","ENG":"I'm so embarrassed every time I hear it.","TWN":"每次聽都覺得羞恥死了，真是的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"무슨 소리야? 저것만큼 우리에 대해 잘 설명해 주는 코멘트가 또 어디 있어?","JPN":"そう？　私たちについてあんなきちんと説明されたコメント、他で見たことないけど。","ENG":"What do you mean? No comment explains who we are better than that!","TWN":"你在說什麼？這不是對我們最好的說明和評價嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"뭘 설명해 줘? 알파트릭스 불매 운동 게시글에 좋아요 하나 찍어 준 거?","JPN":"何が説明よ。アルファトリックス不買運動コメントに、いいね一つしかなかったくせに。","ENG":"Explains what, exactly? How we gave one \\"like\\" to the social media post boycotting Alphatrix products?","TWN":"說明什麼了？抵制阿爾法崔克斯運動的聊天串有幾個讚？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"두 개였어! 나랑 앨버트 것까지!","JPN":"二つ！　アルバートの分も含めて！","ENG":"Two likes! Mine and Albert's!","TWN":"兩個讚！我，還有亞伯特的！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"괜찮아, 매버릭. 넘버 2는 우리 조직에 들어온 지 얼마 안 되어서 그래.","JPN":"大丈夫、マーベリック。ナンバー2はこの組織に入ったばかりだから。","ENG":"It's okay, Maverick. Number 2 hasn't acclimated to our group yet, that's all.","TWN":"沒關係，麥伯利。NO.2是因為剛進組織不久，還沒適應過來。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그리고 9인방이라니, 나 오기 전에도 너네 다 합쳐서 세 명밖에 없었잖아.","JPN":"それに9人組って、アタシが来る前だってアンタたち合わせて3人しかいなかったじゃない。","ENG":"And \\"Nine\\" Great Hackers? There was only three of you before I came... and it doesn't even match our name.","TWN":"還有，9人幫是什麼啦，在我來之前也只有3個人啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"크흠. 그건 일종의 TO 같은 거야. 빈 자리가 있어야 실력자들을 뽑을 수 있으니까.","JPN":"ゴホン。それはある種のTOみたいなもので、常に空席がなきゃ実力者たちを引き抜けない。","ENG":"Ahem. It's a sort of a designated vacancy. We need to leave some slots open to accept new talent.","TWN":"喔，那是某種成員編制表之類的啦，因為要為將來選拔出的人才留空位啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NICK_NULL","text":{"KOREA":"그냥 멋있어 보여서 9인방으로 한 게 아니라?","JPN":"カッコいい響きだったから9人組にしたんじゃなくて？","ENG":"You didn't just randomly pick 9 because it sounded cool?","TWN":"你只是因為聽起來很帥所以叫9人幫吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"빨리 무슨 핑계라도 대 봐. 이러다 들키겠어.","JPN":"早く何か言い訳でもいいからして。このままじゃバレちゃう。","ENG":"Come on, say something. She's going to catch on.","TWN":"趕快隨便想個藉口，這樣下去會被發現的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그런 말은 개인 채널로 해, 얼간아!","JPN":"そういう話は個人チャットですべきでしょ、バカ！","ENG":"You should send that as a DM, you moron!","TWN":"這種話在個人頻道裡說啦，笨蛋！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>GAP DARK 님이 접속하셨습니다.</color>","JPN":"<color=#ffd34c>GAP DARKさんがログインしました。</color>","ENG":"<color=#ffd34c>GAP DARK has logged in.</color>","TWN":"<color=#ffd34c>GAP DARK先生上線了。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NICK_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};